def aList(n: int) -> list[int]:
    A = [1] * (n + 1 )
    for i in range(2, n + 1):
        for k in range(2, n + 1):
            A[k] = i * A[k-1] + (k % 2) * A[k]
    return A[1:]
def a(n): return aList(n)[-1]
